import React from 'react';
import { IntTableHeader } from '../../types';
import { FootPrints } from 'types';
import SortableTable from './SortableTable';
// import roundPercentageToDecimal from './utils/Utils';

interface NodeStatisticsProps {
  nodeList: FootPrints[];
  noDataText: string;
  title: string;
}

const tableHeaders: IntTableHeader[] = [
  // { text: 'Name', dataField: 'name', sort: true, isKey: true },
  // { text: 'Time', dataField: 'time', sort: true, ignoreLiteral: ' ms' },
  // { text: 'Requests', dataField: 'requests', sort: true, ignoreLiteral: '' },
  // { text: 'Error Rate', dataField: 'error_rate', sort: true, ignoreLiteral: '%' },
  { text: 'interface', dataField: 'interface', sort: true, isKey: true },
  { text: 'reply', dataField: 'reply', sort: true, ignoreLiteral: '' },
  { text: 'interfaceType', dataField: 'interfaceType', sort: true, ignoreLiteral: '' },
  { text: 'interfaceIp', dataField: 'interfaceIp', sort: true, ignoreLiteral: '' },
  { text: 'host', dataField: 'host', sort: true, ignoreLiteral: '' },
  { text: 'packet', dataField: 'packet', sort: true, ignoreLiteral: '' },
  { text: 'src', dataField: 'src', sort: true, ignoreLiteral: '' },
  { text: 'dst', dataField: 'dst', sort: true, ignoreLiteral: '' },
];

function getStatisticsTable(noDataText: string, nodeList: FootPrints[]) {
  if (nodeList.length > 0) {
    return (
      <SortableTable
        tableHeaders={tableHeaders}
        data={nodeList.map((node: FootPrints) => {
          return {
            interface: node.interface,
            reply: node.reply,
            interfaceType: node.interface_type,
            interfaceIp: node.interface_ip,
            host: node.host,
            packet: node.packet,
            src: node.src,
            dst: node.dst,
          };
        })}
      />
    );
  } else {
    return <div className="no-data--selection">{noDataText}</div>;
  }
}

export const NodeStatistics: React.FC<NodeStatisticsProps> = ({ nodeList, noDataText, title }) => {
  return (
    <div>
      <div className="secondHeader--selection">{title}</div>
      {getStatisticsTable(noDataText, nodeList)}
    </div>
  );
};
