const options = {
  name: 'cola',
  animate: true, // whether to show the layout as it's running 是否在运行时显示布局
  refresh: 1, // number of ticks per frame; higher is faster but more jerky 每帧的刻度数； 越高越快但越不稳定
  maxSimulationTime: 3000, // max length in ms to run the layout 运行布局的最大长度（以毫秒为单位）
  ungrabifyWhileSimulating: false, // so you can't drag nodes during layout 所以你不能在布局过程中拖动节点
  fit: true, // set by controller // on every layout reposition of nodes, fit the viewport 由控制器设置 // 在节点的每个布局重新定位上，适合视口
  padding: 90, // padding around the simulation 在模拟周围填充
  boundingBox: undefined as undefined, // constrain layout bounds; { x1, y1, x2, y2 } or { x1, y1, w, h } 约束布局边界；
  nodeDimensionsIncludeLabels: false, // whether labels should be included in determining the space used by a node
  // 标签是否应该包含在确定节点使用的空间中

  // layout event callbacks 布局事件回调
  ready: function () {}, // on layoutready
  stop: function () {}, // on layoutstop

  // positioning options 定位选项
  randomize: false, // use random node positions at beginning of layout 在布局开始时使用随机节点位置
  avoidOverlap: true, // if true, prevents overlap of node bounding boxes 如果为真，则防止节点边界框重叠
  handleDisconnected: true, // if true, avoids disconnected components from overlapping 如果为真，则避免断开连接的组件重叠
  convergenceThreshold: 0.01, // when the alpha value (system energy) falls below this value, the layout stops 当 alpha 值（系统能量）低于该值时，布局停止
  nodeSpacing: function (node: any) {
    return 50;
  }, // extra spacing around nodes 节点周围的额外间距
  flow: undefined as undefined, // use DAG/tree flow layout if specified, e.g. { axis: 'y', minSeparation: 30 } 如果指定，则使用 DAG/树流布局，例如
  alignment: undefined as undefined, // relative alignment constraints on nodes, e.g. function( node ){ return { x: 0, y: 1 } } 节点上的相对对齐约束，例如
  gapInequalities: undefined as undefined, // list of inequality constraints for the gap between the nodes, e.g. [{"axis":"y", "left":node1, "right":node2, "gap":25}]
  // 节点之间间隙的不等式约束列表，例如
  // different methods of specifying edge length 指定边长的不同方法
  // each can be a constant numerical value or a function like `function( edge ){ return 2; }`
  // 每个都可以是一个常量数值或函数，如`function( edge ){ return 2; }`
  edgeLength: undefined as undefined, // sets edge length directly in simulation 直接在模拟中设置边长
  edgeSymDiffLength: undefined as undefined, // symmetric diff edge length in simulation 模拟中的对称差分边长
  edgeJaccardLength: undefined as undefined, // jaccard edge length in simulation 模拟中的杰卡德边长

  // iterations of cola algorithm; uses default values on undefined 可乐算法的迭代； 在 undefined 上使用默认值
  unconstrIter: 50, // set by controller // unconstrained initial layout iterations 由控制器设置 // 不受约束的初始布局迭代
  userConstIter: undefined as undefined, // initial layout iterations with user-specified constraints 具有用户指定约束的初始布局迭代
  allConstIter: undefined as undefined, // initial layout iterations with all constraints including non-overlap 具有所有约束的初始布局迭代，包括非重叠

  // infinite layout options 无限的布局选项
  infinite: false, // overrides all other options for a forces-all-the-time mode 覆盖始终强制模式的所有其他选项
};

export default options;
