import _, { assign } from 'lodash';
import { isPresent } from './utils/Utils';
import { PanelController } from '../panel/PanelController';
import {
  GraphDataElement,
  IntGraph,
  IntGraphEdge,
  IntGraphEdgeData ,
  IntGraphMetrics,
  IntGraphNode,
  EnGraphNodeType,
  FootPrints,
  GlobalElement,
  EdgeLabel,
} from '../types';
import NodeTree from './node_tree';
import NodeSubstitutor from './node_substitutor';

class GraphGenerator {
  controller: PanelController;
  nodeSubstitutor: NodeSubstitutor;

  constructor(controller: PanelController) {
    this.controller = controller;
    this.nodeSubstitutor = new NodeSubstitutor();
  }

  _createNode(dataElements: GraphDataElement[], nodeTree: NodeTree, key: string): IntGraphNode | undefined {
    // console.log('key:', key);
    if (!dataElements || dataElements.length <= 0) {
      return undefined;
    }

    // const sumMetrics = this.controller.getSettings(true).sumTimings;
    var nodeName: string;
    nodeName = key;
    if (nodeName === '' || nodeName === undefined || nodeName === null) {
      nodeName = 'undefined';
    }

    const nodeType =  EnGraphNodeType.INTERNAL ;

    const metrics: IntGraphMetrics = {};

    const node: IntGraphNode = {
      data: {
        id: nodeName,
        label: nodeName,
        external_type: nodeType,
        type: nodeType,
        layer: 0,
        metrics,
        namespace: [],
        healthLevel: 1,
        host: nodeName.split('-')[1],
      },
    };
    // console.log('dataElements:', dataElements);
    // console.log('nodeName', nodeName);
    // 填充 这个网卡上查询到的路由信息
    var reqFootPrints: FootPrints[] = [];
    dataElements.map((dataElement) => {
      const req: FootPrints[] = dataElement.data
        .filter((element) => {
          return element.reply === false;
        })
        .map((element) => {
          const footPrint: FootPrints = {
            interface: element.interface,
            reply: element.reply,
            interface_type: element.interface_type,
            interface_ip: element.interface_ip,
            host: element.host,
            packet: element.packet,
            src: element.src,
            dst: element.dst,
          };
          return footPrint;
        });
      for (let i = req.length - 1; i >= 0; i--) {
        if (req[i].packet || req[i].interface + '-' + req[i].host === nodeName) {
          // console.log('req[i]', req[i]);
          reqFootPrints.push(req[i]);
        }
      }
    });

    // console.log('dataElements:',dataElements);
  
    var repFootPrints: FootPrints[] = [];
    dataElements.map((dataElement) => {
      // console.log('dataElement:',dataElement);
      const rep: FootPrints[] = dataElement.data
        .filter((element) => {
          return element.reply === true;
        })
        .map((element) => {
          const footPrint: FootPrints = {
            interface: element.interface,
            reply: element.reply,
            interface_type: element.interface_type,
            interface_ip: element.interface_ip,
            host: element.host,
            packet: element.packet,
            src: element.src,
            dst: element.dst,
          };
          return footPrint;
        });
        // console.log('rep:',rep);
      for (let i = rep.length - 1; i >= 0; i--) {
        if (rep[i].packet || rep[i].interface + '-' + rep[i].host === nodeName) {
          // console.log('rep[i]', rep[i]);
          repFootPrints.push(rep[i]);
        }
      }
    });
    const itf = nodeName.split('-')[0];
    // console.log('itf:', itf);
    let itfIp = '';
    for (let reqFootPrint of reqFootPrints) {
      if (reqFootPrint.interface === itf && reqFootPrint.interface_ip) {
        itfIp = reqFootPrint.interface_ip;
        break;
      }
    }
    if (itfIp === '') {
      for (let repFootPrint of repFootPrints) {
        if (repFootPrint.interface === itf && repFootPrint.interface_ip) {
          itfIp = repFootPrint.interface_ip;
          break;
        }
      }
    }
    var nulNum = 0;
    for (let reqFootPrint of reqFootPrints) {
      if (!reqFootPrint.packet) {
        nulNum++;
      }
    }
    for (let repFootPrint of repFootPrints) {
      if (!repFootPrint.packet) {
        nulNum++;
      }
    }
    if (nulNum === 0) {
      node.data.healthLevel = 1;
    } else if (nulNum > 0 && nulNum < repFootPrints.length + reqFootPrints.length) {
      node.data.healthLevel = 2;
    } else {
      node.data.healthLevel = 3;
    }
    if (itfIp !== '') {
      metrics.itfIp = itfIp;
    }
    metrics.rate = 50;
    metrics.response_time = 5000;
    metrics.reqFootPrints = reqFootPrints;
    metrics.replyFootPrints = repFootPrints;
    nodeTree.addNode(node);
    this.nodeSubstitutor.add(node);
    return node;
  }

  // 创建缺失节点
  _createMissingNodes(data: GraphDataElement[], nodes: IntGraphNode[]): IntGraphNode[] {
    const existingNodeNames = _.map(nodes, (node) => node.data.id);
    const expectedNodeNames = _.uniq(_.flatMap(data, (dataElement) => [dataElement.source, dataElement.target])).filter(
      isPresent
    );
    const missingNodeNames = _.difference(expectedNodeNames, existingNodeNames);
    const missingNodes = _.map(missingNodeNames, (name) => {
      let nodeType: EnGraphNodeType;
      let external_type: string | undefined;

      // derive node type 派生节点类型
      nodeType = EnGraphNodeType.INTERNAL;
      var value: IntGraphNode = {
        data: {
          id: name,
          type: nodeType,
          external_type: external_type,
          metrics: {},
          layer: 0,
        },
      };
      this.nodeSubstitutor.add(value);
      return value;
    });
    return missingNodes;
  }

  _createNodes(data: GraphDataElement[]): IntGraphNode[] {
    var tree = new NodeTree();
    const filteredData = _.filter(
      data,
      (dataElement) =>
        dataElement.source !== dataElement.target ||
        (_.has(dataElement, 'target') && !_.has(dataElement, 'target')) ||
        (!_.has(dataElement, 'target') && _.has(dataElement, 'target'))
    );
    // console.log('filteredData:', filteredData);
    const targetGroupsTa = _.groupBy(filteredData, 'target');
    const targetGroupsSo = _.groupBy(filteredData, 'source');
    // console.log('targetGroupsTa:', targetGroupsTa);
    // console.log('targetGroupsSo:', targetGroupsSo);
    for (let key in targetGroupsSo) {
      // 处理一下这个分组数据
      if (targetGroupsTa[key]) {
        targetGroupsTa[key] = targetGroupsTa[key].concat(targetGroupsSo[key]);
      }
    }
    const targetGroups = assign({}, targetGroupsSo, targetGroupsTa);
    // console.log('targetGroups 合并后:', targetGroups);
    const explicitlyNamedNodes = _.map(targetGroups, (group, key) => this._createNode(group, tree, key)).filter(
      isPresent
    );
    // console.log('filteredData:', filteredData);
    // console.log('explicitlyNamedNodes:', explicitlyNamedNodes);
    // ensure that all nodes exist, even we have no data for them 确保所有节点都存在，即使我们没有它们的数据
    const missingNodes = this._createMissingNodes(filteredData, explicitlyNamedNodes);
    // console.log('missingNodes:', missingNodes);
    missingNodes.forEach((node) => tree.addNode(node));
    const allNodes = tree.getNodesFromLayer(this.controller.state.currentLayer);
    return allNodes;
  }

  _resolveSubstitute(name: string): string {
    return this.nodeSubstitutor.substituteUntilLayer(
      name,
      this.controller.state.currentLayer,
      this.controller.maxLayer
    );
  }

  _createEdge(dataElement: GraphDataElement): IntGraphEdge | undefined {
    // console.log('dataElement:', dataElement);
    var { source, target } = dataElement;
    if (source === undefined || target === undefined) {
      console.error('source and target are necessary to create an edge', dataElement);
      return undefined;
    }

    const metrics: IntGraphMetrics = {};

    source = this._resolveSubstitute(source);
    target = this._resolveSubstitute(target);
    if (source === target) {
      return undefined;
    }

    const edge: IntGraphEdge = {
      data: {
        source,
        target,
        metrics,
      },
    };
    // console.log('edge1:',edge);
    
    metrics.isReply = dataElement.data[0].reply;
    const edgeLabels: EdgeLabel[] = [];
    for (let datum of dataElement.data) {
      if (datum.src) {
        const edgeLabel: EdgeLabel = {
          src: datum.src,
          dst: datum.dst,
        };
        edgeLabels.push(edgeLabel);
      }
    }
    const uniqueEdgeLabels = edgeLabels.filter((edgeLabel, index, self) => index === self.findIndex((p) => p.src === edgeLabel.src && p.dst === edgeLabel.dst));
    metrics.edgeLabels = uniqueEdgeLabels;
    // console.log('edge:',edge);
    return edge;
  }

  // 解析边数据
  _resolveEdgeMap(edges: IntGraphEdge[]) {
    var edgeMap: Map<string, IntGraphEdge[]> = new Map();
    edges.forEach((edge) => {
      if (edgeMap.get(edge.data.source + '-' + edge.data.target)) {
        edgeMap.get(edge.data.source + '-' + edge.data.target).push(edge);
      } else {
        edgeMap.set(edge.data.source + '-' + edge.data.target, [edge]);
      }
    });
    return edgeMap;
  }

  // 合并数据
  _mergeArrayOfEdges(edges: IntGraphEdge[]) {
    const mergedEdge: IntGraphEdge = {
      data: {
        source: '',
        target: '',
        metrics: {},
      },
    };
    edges.forEach((edge) => {
      if (mergedEdge.data.source === '') {
        mergedEdge.data.source = edge.data.source;
        // mergedEdge.data.source = edge.data.source;
      }
      if (mergedEdge.data.target === '') {
        mergedEdge.data.target = edge.data.target;
        // mergedEdge.data.target = edge.data.target;
      }
    });


    return mergedEdge;
  }

  _edgeMapToMergedEdges(edgeMap: Map<string, IntGraphEdge[]>) {
    var edges: IntGraphEdge[] = [];
    for (const entry of edgeMap.values()) {
      edges.push(this._mergeArrayOfEdges(entry));
    }
    return edges;
  }

  _mergeEdges(edges: IntGraphEdge[]) {
    const edgeMap = this._resolveEdgeMap(edges);
    this._edgeMapToMergedEdges(edgeMap);
    return edges;
  }

  _createEdges(data: GraphDataElement[]): IntGraphEdge[] {
    const filteredData = _(data)
      .filter((e) => !!e.source)
      .filter((e) => e.source !== e.target)
      .filter((e) => e.target !== null || e.source !== null)
      .value();
    // console.log('filteredData:', filteredData);
    const edges = _.map(filteredData, (element) => this._createEdge(element));
    const filteredEdges = edges.filter(isPresent);
    // console.log('filteredEdges:',filteredEdges);
    
    return this._mergeEdges(filteredEdges);
  }

  _filterData(graph: IntGraph): IntGraph {
    const { filterEmptyConnections: filterData } = this.controller.getSettings(true);
    const result = graph.result;
    const suggestions = graph.suggestions;
    if (filterData) {
      const filteredGraph: IntGraph = {
        nodes: [],
        edges: [],
        result: result,
        suggestions: suggestions,
      };
      // filter empty connections 过滤空连接
      filteredGraph.edges = _.filter(graph.edges, (edge) => _.size(edge.data.metrics) > 0);
      filteredGraph.nodes = graph.nodes;
      return filteredGraph;
    } else {
      return graph;
    }
  }

  // 生成图表
  generateGraph(globalElement: GlobalElement) {
    const nodes = this._createNodes(globalElement.graphDataElement);

    const edges = this._createEdges(globalElement.graphDataElement);
    if (edges.length == 5) {
      const data: IntGraphEdgeData = {
        source: "",
        target: "",
      };
      data.target = edges[0].data.source;
      data.source = edges[4].data.target;
      data.metrics = edges[0].data.metrics;
      const newEdge: IntGraphEdge = {data};
      edges.push(newEdge);
    }
    if (edges.length == 3) {
      const data: IntGraphEdgeData = {
        source: "",
        target: "",
      };
      data.target = edges[0].data.source;
      data.source = edges[2].data.target;
      data.metrics = edges[0].data.metrics;
      const newEdge: IntGraphEdge = {data};
      edges.push(newEdge);
    }
    const result = globalElement.result;
    const suggestions = globalElement.suggestions;
    const graph: IntGraph = {
      nodes,
      edges,
      result,
      suggestions,
    };
    const filteredGraph = this._filterData(graph);
    // console.log('filteredGraph:',filteredGraph);
    
    return filteredGraph;
  }

  _updateMaxLayer(layer: number) {
    if (layer > this.controller.maxLayer) {
      this.controller.maxLayer = layer;
    }
  }
}

export default GraphGenerator;
