import _ from 'lodash';
import cytoscape from 'cytoscape';
import { ServiceDependencyGraph } from '../serviceDependencyGraph/ServiceDependencyGraph';
import ParticleEngine from './particle_engine';
import {
  CyCanvas,
  Particle,
  EnGraphNodeType,
  Particles,
  IntGraphMetrics,
  ScaleValue,
  DrawContext,
  Rectangle,
  Point,
  NodeRange,
} from '../../types';
import assetUtils from '../asset_utils';
import CollisionDetector from './collision_detector';

const scaleValues: ScaleValue[] = [
  { unit: 'ms', factor: 1 },
  { unit: 's', factor: 1000 },
  { unit: 'm', factor: 60000 },
];

export default class CanvasDrawer {
  readonly colors = {
    default: '#bad5ed',
    background: '#212121',
    edge: '#505050',
    status: {
      warning: 'orange',
    },
    req: 'rgb(105,170,241)',
    rep: 'rgb(153,253,161)',
    healthyColor: 'rgb(87, 148, 242)',
    dangerColor: 'rgb(196, 22, 42)',
    noDataColor: 'rgb(123, 123, 138)',
    warnColor: 'rgb(231,227,48)',
  };

  readonly donutRadius: number = 15;

  controller: ServiceDependencyGraph;

  // 核心对象是您与图形的接口。它是您进入 Cytoscape.js 的入口点：该库的所有功能都可以通过该对象访问
  cytoscape: cytoscape.Core;

  // 可为<canvas>元素的绘图表面提供 2D 渲染上下文。它用于绘制形状，文本，图像和其他对象。
  context: CanvasRenderingContext2D;

  cyCanvas: CyCanvas;

  // 提供用于操纵<canvas>元素的布局和表示的属性和方法
  canvas: HTMLCanvasElement;

  offscreenCanvas: HTMLCanvasElement;

  offscreenContext: CanvasRenderingContext2D;

  // 帧计数器
  frameCounter = 0;

  fpsCounter = 0;

  particleImage: HTMLImageElement;

  // 像素比
  pixelRatio: number;

  imageAssets: any = {};

  // 选择邻域
  selectionNeighborhood: cytoscape.Collection;

  particleEngine: ParticleEngine;

  collisionDetector: CollisionDetector;

  // 最后渲染时间
  lastRenderTime = 0;

  map: any;

  constructor(ctrl: ServiceDependencyGraph, cy: cytoscape.Core, cyCanvas: CyCanvas) {
    this.cytoscape = cy;
    this.cyCanvas = cyCanvas;
    this.controller = ctrl;
    this.particleEngine = new ParticleEngine(this);
    this.collisionDetector = new CollisionDetector();

    this.pixelRatio = window.devicePixelRatio || 1;

    this.canvas = cyCanvas.getCanvas();
    // 建立一个 CanvasRenderingContext2D 二维渲染上下文。
    const ctx = this.canvas.getContext('2d');
    if (ctx) {
      this.context = ctx;
    } else {
      console.error('Could not get 2d canvas context.');
    }

    this.offscreenCanvas = document.createElement('canvas');
    this.offscreenContext = this.offscreenCanvas.getContext('2d');
    this.repaint(true);
  }

  // 获得时间刻度
  _getTimeScale(timeUnit: string) {
    const scale: any = {};
    for (const scaleValue of scaleValues) {
      scale[scaleValue.unit] = scaleValue.factor;
      if (scaleValue.unit === timeUnit) {
        return scale;
      }
    }
    return scale;
  }

  resetAssets() {
    this.imageAssets = {};
  }

  _loadImage(imageUrl: string, assetName: string) {
    const that = this;

    const loadImage = (url: string, asset: keyof typeof that.imageAssets) => {
      const image = new Image();
      that.imageAssets[asset] = {
        image,
        loaded: false,
      };

      return new Promise((resolve, reject) => {
        image.onload = () => resolve(asset);
        image.onerror = () => reject(new Error(`load ${url} fail`));
        image.src = url;
      });
    };
    loadImage(imageUrl, assetName).then((asset: any) => {
      that.imageAssets[asset].loaded = true;
    });
  }

  _isImageLoaded(assetName: string) {
    if (_.has(this.imageAssets, assetName) && this.imageAssets[assetName].loaded) {
      return true;
    } else {
      return false;
    }
  }

  _getAsset(assetName: string, relativeUrl: string) {
    if (!_.has(this.imageAssets, assetName)) {
      const assetUrl = assetUtils.getAssetUrl(relativeUrl);
      this._loadImage(assetUrl, assetName);
    }

    if (this._isImageLoaded(assetName)) {
      return this.imageAssets[assetName].image;
    } else {
      return null;
    }
  }

  start() {
    console.log('Starting graph logic');

    const that = this;
    const repaintWrapper = () => {
      that.repaint();
      // 告诉浏览器你希望执行一个动画，并在重绘之前，请求浏览器执行一个特定的函数来更新动画。
      window.requestAnimationFrame(repaintWrapper);
    };

    window.requestAnimationFrame(repaintWrapper);
    // 当设定好间隔时间后，function 会定期执行。
    // 该方法重复调用一个函数或执行一个代码片段，在每次调用之间具有固定的时间间隔。
    setInterval(() => {
      that.fpsCounter = that.frameCounter;
      that.frameCounter = 0;
    }, 1000);
  }

  startAnimation() {
    this.particleEngine.start();
  }

  stopAnimation() {
    this.particleEngine.stop();
    this.repaint();
  }

  _skipFrame() {
    const now = Date.now();
    // elapsedTime
    const elapsedTime = now - this.lastRenderTime;

    if (this.particleEngine.count() > 0) {
      return false;
    }

    if (!this.controller.getSettings(true).animate && elapsedTime < 1000) {
      return true;
    }
    return false;
  }

  // 重绘
  repaint(forceRepaint = false) {
    if (!forceRepaint && this._skipFrame()) {
      return;
    }
    this.lastRenderTime = Date.now();

    const ctx = this.context;
    const cyCanvas = this.cyCanvas;
    const offscreenCanvas = this.offscreenCanvas;
    const offscreenContext = this.offscreenContext;
    this.collisionDetector.reset();

    offscreenCanvas.width = this.canvas.width;
    offscreenCanvas.height = this.canvas.height;
    // 离屏渲染 设置物体变换
    this._setTransformation(offscreenContext);
    // 获取一个空集合。
    this.selectionNeighborhood = this.cytoscape.collection();
    // 获取图表中与选择器或过滤器函数匹配的元素。
    const selection = this.cytoscape.$(':selected');
    // cytoscape.SingularElementArgument 边或节点
    selection.forEach((element: cytoscape.SingularElementArgument) => {
      this.selectionNeighborhood.merge(element);
      if (element.isNode()) {
        // 获取元素的开邻域。
        const neighborhood = element.neighborhood();
        this.selectionNeighborhood.merge(neighborhood);
      } else {
        // 获取这条边的源节点。
        const source = element.source();
        // 获取这条边的目标节点。
        const target = element.target();
        this.selectionNeighborhood.merge(source);
        this.selectionNeighborhood.merge(target);
      }
    });

    // 画节点
    this._drawNodes(offscreenContext);
    if (this.controller.data.result == true) {
        // 画边
        this._drawEdgeAnimation(offscreenContext);
    }
    // 画同节点范围框
    this._drawNodeRange(offscreenContext);
    // cyCanvas.resetTransform(ctx);
    cyCanvas.clear(ctx);
    if (offscreenCanvas.width > 0 && offscreenCanvas.height > 0) {
      // 其中 image 是 image 或者 canvas 对象，x 和 y 是其在目标 canvas 里的起始坐标。
      ctx.drawImage(offscreenCanvas, 0, 0);
    }
  }

  _setTransformation(ctx: CanvasRenderingContext2D) {
    // 获取当前的平移位置。
    const pan = this.cytoscape.pan();
    // 获取缩放级别。
    const zoom = this.cytoscape.zoom();
    // 将当前的变形矩阵重置为单位矩阵，然后用相同的参数调用 transform方法。
    // 从根本上，该方法是取消了当前变形，然后设置为指定的变形，一步完成。
    // a (m11) 水平缩放。b (m12) 垂直倾斜。c (m21) 水平倾斜。d (m22)垂直缩放。e (dx) 水平移动。f (dy) 垂直移动。
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    // 它用来移动 canvas 和它的原点到一个不同的位置。
    // *x *是左右偏移量，y 是上下偏移量
    ctx.translate(pan.x * this.pixelRatio, pan.y * this.pixelRatio);
    // 缩放画布的水平和垂直的单位
    // x 为水平缩放因子，y 为垂直缩放因子，如果比 1 小，会缩小图形，如果比 1 大会放大图形。默认值为 1，为实际大小。
    // 如果参数为负实数，相当于以 x 或 y 轴作为对称轴镜像反转
    ctx.scale(zoom * this.pixelRatio, zoom * this.pixelRatio);
  }

  // 画边动画
  _drawEdgeAnimation(ctx: CanvasRenderingContext2D) {
    const now = Date.now();
    // 保存画布 (canvas) 的所有状态
    // Canvas 状态存储在栈中，每当save()方法被调用后，当前的状态就被推送到栈中保存。
    // 你可以调用任意多次 save方法。每一次调用 restore 方法，上一个保存的状态就从栈中弹出，所有设定都恢复。
    ctx.save();

    const edges = this.cytoscape.edges().toArray();
    const hasSelection = this.selectionNeighborhood.size() > 0;
    // 透明的边
    const transparentEdges = edges.filter((edge) => hasSelection && !this.selectionNeighborhood.has(edge));
    // 不透明边
    const opaqueEdges = edges.filter((edge) => !hasSelection || this.selectionNeighborhood.has(edge));

    // 设置透明度值
    ctx.globalAlpha = 0.25;
    this._drawEdges(ctx, transparentEdges, now);
    ctx.globalAlpha = 1;
    this._drawEdges(ctx, opaqueEdges, now);
    // 恢复 canvas 状态。
    ctx.restore();
  }

  // 画边
  _drawEdges(ctx: CanvasRenderingContext2D, edges: cytoscape.EdgeSingular[], now: number) {
    // const cy = this.cytoscape;
    for (const edge of edges) {      
      // 获取边缘结束的位置，朝向源节点。
      const sourcePoint = edge.sourceEndpoint();
      // 获取边缘结束的位置，朝向目标节点。
      const targetPoint = edge.targetEndpoint();      
      this._drawEdgeLine(ctx, edge, sourcePoint, targetPoint);
      this._drawEdgeParticles(ctx, edge, sourcePoint, targetPoint, now);
      this._drawEdgeLabel(ctx, edge);
    }
  }

  _drawEdgeLine(
    ctx: CanvasRenderingContext2D,
    edge: cytoscape.EdgeSingular,
    sourcePoint: cytoscape.Position,
    targetPoint: cytoscape.Position
  ) {
    // 新建一条路径，生成之后，图形绘制命令被指向到路径上生成路径。
    ctx.beginPath();
    ctx.moveTo(sourcePoint.x, sourcePoint.y);
    // 绘制一条从当前位置到指定 x 以及 y 位置的直线。
    ctx.lineTo(targetPoint.x, targetPoint.y);
    // 读取和写入与元素关联的开发人员定义的数据。
    const metrics = edge.data('metrics');
    // console.log('metrics:', metrics);
    // 获取对象路径处的属性值。 如果解析值未定义，则使用 defaultValue 代替它。
    // let base;
    if (!this.selectionNeighborhood.empty() && this.selectionNeighborhood.has(edge)) {
      // 设置线条宽度。
      ctx.lineWidth = 1.5;
      // base = 140;
    } else {
      ctx.lineWidth = 1;
      // base = 80;
    }
    const isReply = metrics.isReply;
    if (isReply) {
      ctx.strokeStyle = this.colors.rep;
    } else {
      ctx.strokeStyle = this.colors.req;
    }
    ctx.stroke();
    // 画箭头
    var theta = 30,
      headlen = 2,
      width = 1,
      angle = (Math.atan2(sourcePoint.y - targetPoint.y, sourcePoint.x - targetPoint.x) * 180) / Math.PI,
      angle1 = ((angle + theta) * Math.PI) / 180,
      angle2 = ((angle - theta) * Math.PI) / 180,
      topX = headlen * Math.cos(angle1),
      topY = headlen * Math.sin(angle1),
      botX = headlen * Math.cos(angle2),
      botY = headlen * Math.sin(angle2);
    ctx.moveTo(targetPoint.x + topX, targetPoint.y + topY);
    ctx.lineTo(targetPoint.x, targetPoint.y);
    ctx.lineTo(targetPoint.x + botX, targetPoint.y + botY);
    ctx.lineWidth = width;
    ctx.stroke();
  }

  // 绘制边缘标签
  _drawEdgeLabel(ctx: CanvasRenderingContext2D, edge: cytoscape.EdgeSingular) {
    const midpoint = edge.midpoint();
    const xMid = midpoint.x;
    const yMid = midpoint.y;
    const metrics: IntGraphMetrics = edge.data('metrics');
    const labels = metrics.edgeLabels;
    let statistics: string[] = [];
    for (let label of labels) {
      const str: string = label.src + '——>' + label.dst;
      statistics.push(str);
    }
    for (let i = 0; i < statistics.length; i++) {
      this._drawLabel(ctx, statistics[i], xMid, yMid - 10 * i, edge, 3);
    }
    // const str: string = labels[0].src + '——>' + labels[0].dst;
    // this._drawLabel(ctx, str, xMid, yMid, edge, 3);

  }

  // 绘制边缘粒子
  _drawEdgeParticles(
    ctx: CanvasRenderingContext2D,
    edge: cytoscape.EdgeSingular,
    sourcePoint: cytoscape.Position,
    targetPoint: cytoscape.Position,
    now: number
  ) {
    const particles: Particles = edge.data('particles');

    if (particles === undefined) {
      return;
    }

    const xVector = targetPoint.x - sourcePoint.x;
    const yVector = targetPoint.y - sourcePoint.y;

    const angle = Math.atan2(yVector, xVector);
    const xDirection = Math.cos(angle);
    const yDirection = Math.sin(angle);

    const xMinLimit = Math.min(sourcePoint.x, targetPoint.x);
    const xMaxLimit = Math.max(sourcePoint.x, targetPoint.x);
    const yMinLimit = Math.min(sourcePoint.y, targetPoint.y);
    const yMaxLimit = Math.max(sourcePoint.y, targetPoint.y);

    const drawContext: DrawContext = {
      ctx,
      now,
      xDirection,
      yDirection,
      xMinLimit,
      xMaxLimit,
      yMinLimit,
      yMaxLimit,
      sourcePoint,
    };

    // normal particles 正常粒子
    ctx.beginPath();
    let index = particles.normal.length - 2;
    while (index >= 0) {
      this._drawParticle(drawContext, particles.normal, index);
      index--;
    }
    // 设置图形的填充颜色。
    ctx.fillStyle = '#f5f5f5';
    ctx.fill();

    // danger particles 危险粒子
    ctx.beginPath();
    index = particles.danger.length - 1;
    while (index >= 0) {
      this._drawParticle(drawContext, particles.danger, index);
      index--;
    }
    const dangerColor = this.colors.dangerColor;
    ctx.fillStyle = dangerColor;
    ctx.fill();
  }

  // 绘制标签
  _drawLabel(
    ctx: CanvasRenderingContext2D,
    label: string,
    cX: number,
    cY: number,
    edge: cytoscape.EdgeSingular,
    txtHeight: number
  ) {
    const labelPadding = 1;
    ctx.font = '4px Arial';

    const labelWidth = ctx.measureText(label).width;
    var xPos = cX - labelWidth / 2;
    var yPos = cY + txtHeight;
    var labelArea: Rectangle = {
      coordinates: {
        x: xPos - labelPadding + 4,
        y: yPos - 6 - labelPadding + 4,
      },
      width: labelWidth,
      height: txtHeight,
    };
    if (!isNaN(labelArea.coordinates.x) || !isNaN(labelArea.coordinates.y) || !isNaN(xPos) || !isNaN(yPos)) {
      // 这是针对所有节点靠得太近以至于标签需要相互重叠的情况。
      const maxRepeats = 1000;
      var repeats = 0;
      while (this.collisionDetector.isColliding(labelArea) && repeats < maxRepeats) {
        const nextPoint = this._getNextPointOnVector(xPos, yPos, edge, 0.999);
        labelArea.coordinates = nextPoint;
        yPos = nextPoint.y;
        xPos = nextPoint.x;
        repeats++;
      }
      this.collisionDetector.addRectangle(xPos - 4, yPos - 4, labelWidth + 12, 12);
    }
    const metrics: IntGraphMetrics = edge.data('metrics');
    const isReply: boolean = metrics.isReply;
    if (isReply) {
      ctx.fillStyle = this.colors.rep;
    } else {
      ctx.fillStyle = this.colors.req;
    }
    // 绘制一个填充的矩形
    ctx.fillRect(xPos - labelPadding, yPos - 5 - labelPadding, labelWidth + 2 * labelPadding, 5 + 2 * labelPadding);
    ctx.fillStyle = this.colors.background;
    // 在指定的 (x,y) 位置填充指定的文本，绘制的最大宽度是可选的。
    ctx.fillText(label, xPos, yPos - 1);
  }

  // 获取向量上的下一个点
  _getNextPointOnVector(x: number, y: number, edge: cytoscape.EdgeSingular, step: number) {
    var yTarget = edge.sourceEndpoint().y;
    var xTarget = edge.sourceEndpoint().x;

    const newPoint: Point = {
      x: xTarget * (1.0 - step) + x * step,
      y: yTarget * (1.0 - step) + y * step,
    };

    return newPoint;
  }

  _drawParticle(drawCtx: DrawContext, particles: Particle[], index: number) {
    const { ctx, now, xDirection, yDirection, xMinLimit, xMaxLimit, yMinLimit, yMaxLimit, sourcePoint } = drawCtx;

    const particle = particles[index];
    // 时间增量
    const timeDelta = now - particle.startTime;
    const xPos = sourcePoint.x + xDirection * timeDelta * particle.velocity;
    const yPos = sourcePoint.y + yDirection * timeDelta * particle.velocity;

    if (xPos > xMaxLimit || xPos < xMinLimit || yPos > yMaxLimit || yPos < yMinLimit) {
      // remove particle
      particles.splice(index, 1);
    } else {
      // draw particle
      ctx.moveTo(xPos, yPos);
      // 画一个以（x,y）为圆心的以 radius 为半径的圆弧（圆），从 startAngle 开始到 endAngle 结束，
      // 按照 anticlockwise 给定的方向（默认为顺时针）来生成。
      ctx.arc(xPos, yPos, 1, 0, 2 * Math.PI, false);
    }
  }

  // 绘制节点
  _drawNodes(ctx: CanvasRenderingContext2D) {
    const that = this;
    const cy = this.cytoscape;
    const nodes = cy.nodes().toArray();
    const pY = nodes[0].position().y;
    // 使节点在一水平线上
    cy.nodes().positions(function(node) {
      return {
        x: node.position().x,
        y: pY
      };
    });
    for (let i = 0; i < nodes.length; i++) {
      const node = nodes[i];
      if (that.selectionNeighborhood.empty() || that.selectionNeighborhood.has(node)) {
        ctx.globalAlpha = 1;
      } else {
        ctx.globalAlpha = 0.25;
      }
      // draw the node
        that._drawNode(ctx, node);
      // 绘制节点标签
      if (cy.zoom() > 1) {
        that._drawNodeLabel(ctx, node);
        // that._drawNodeSrcLabel(ctx, node);
      }
    }
    // 绘制result、suggestions标签
    //this._drawTxt(ctx, nodes[nodes.length - 1]);
  }

  _drawNode(ctx: CanvasRenderingContext2D, node: cytoscape.NodeSingular) {
    const type = node.data('type');
    if (type === EnGraphNodeType.INTERNAL) {
      // drawing the donut 画圈
      // this._drawDonut(ctx, node, 15, 5, 0.5, [errorPct, unknownPct, healthyPct]);
      this._drawRectangle(ctx, node,15, 25, 0.5, 5);
    } 
  }

  _drawNodeRange(ctx: CanvasRenderingContext2D) {
    const cy = this.cytoscape;
    const nodes = cy.nodes().toArray();
    const nodeRanges: NodeRange[] = [];
    const defWidth = 100;
    const defHeight = 80;
    const rangeWidth = 50;
    const rangeHeight = 30;
    // 处理node数据分组
    const res = nodes.reduce((result, item) => {
      // console.log('result:', result);
      // console.log('item:', item);
      let index = result.findIndex((it) => it.host === item.data().host);
      if (index === -1) {
        result.push({
          host: item.data().host,
          nodes: [item],
        });
      } else {
        result[index].nodes.push(item);
      }
      return result;
    }, []);
    // console.log('res:',res);

    for (let i = 0; i < res.length; i++) {
      const nodes = res[i].nodes;
      // console.log('nodes:', nodes);
      // 找到同一主机下最左上位置的接口节点 和 最右下位置的接口节点
      let posXl = nodes[0].position().x;
      let posYl = nodes[0].position().y;
      let posXr = nodes[0].position().x;
      let posYr = nodes[0].position().y;
      for (let j = 0; j < nodes.length; j++) {
        posXl = nodes[j].position().x < posXl ? nodes[j].position().x : posXl;
        posYl = nodes[j].position().y > posYl ? nodes[j].position().y : posYl;
        posXr = nodes[j].position().x > posXr ? nodes[j].position().x : posXr;
        posYr = nodes[j].position().y < posYr ? nodes[j].position().y : posYr;
      }
      const width = Math.abs(posXr - posXl) > defWidth ? Math.abs(posXr - posXl) + rangeWidth * 2 : defWidth;
      const height = Math.abs(posYl - posYr) > defHeight ? Math.abs(posYl - posYr) + rangeHeight : defHeight;
      const range: NodeRange = {
        host: res[i].host,
        posX: posXl - rangeWidth,
        postY: posYl - height / 2,
        width: width,
        height: height,
      };
      nodeRanges.push(range);
    }

    // console.log('nodeRanges:', nodeRanges);
    for (let nodeRange of nodeRanges) {
      ctx.strokeStyle = 'rgb(0,113,245)';
      // 画虚线
      ctx.setLineDash([3, 3, 3]);
      ctx.globalAlpha = 0.5;
      ctx.strokeRect(nodeRange.posX, nodeRange.postY, nodeRange.width, nodeRange.height);
      // host文字
      const label = nodeRange.host;
      ctx.font = '6px Arial';
      const labelPadding = 1;
      const labelWidth = ctx.measureText(label).width;
      ctx.globalAlpha = 1;
      ctx.fillStyle = 'rgb(144,204,231)';
      ctx.fillRect(
        nodeRange.posX + nodeRange.width / 2 - (labelWidth - labelPadding) / 2,
        nodeRange.postY - labelPadding + 3,
        labelWidth + 2 * labelPadding,
        6 + 2 * labelPadding
      );
      ctx.fillStyle = this.colors.background;
      ctx.fillText(
        label,
        nodeRange.posX + nodeRange.width / 2 - (labelWidth - labelPadding) / 2,
        nodeRange.postY - labelPadding + 9
      );
    }
  }

  _drawNodeLabel(ctx: CanvasRenderingContext2D, node: cytoscape.NodeSingular) {
    const pos = node.position();
    let label: string = node.id();
    const labelPadding = 1;

    if (this.selectionNeighborhood.empty() || !this.selectionNeighborhood.has(node)) {
      if (label.length > 30) {
        label = label.substr(0, 7) + '...' + label.slice(-7);
      }
    }

    ctx.font = '6px Arial';

    const labelWidth = ctx.measureText(label).width;
    const xPos = pos.x - labelWidth / 2;
    var yPos = pos.y + node.height() * 0.8;
    ctx.fillStyle = this.colors.default;
    ctx.fillRect(xPos - labelPadding, yPos - 6 - labelPadding, labelWidth + 2 * labelPadding, 6 + 2 * labelPadding);
    ctx.fillStyle = this.colors.background;
    ctx.fillText(label, xPos, yPos);
  }

  // 画矩形
  _drawRectangle(
    ctx: CanvasRenderingContext2D,
    node: cytoscape.NodeSingular,
    long: number,
    width: number,
    strokeWidth: number,
    storkeWidth2: number
  ) {
    // node.position().x 节点的中心位置
    const cX = node.position().x - width / 2;
    const cY = node.position().y- long / 2;
    // const { healthyColor, dangerColor, noDataColor, warnColor } = this.controller.getSettings(true).style;
    // const colors = [dangerColor, noDataColor, healthyColor, warnColor];
    // console.log('colors:', colors);
    let midColor = this.colors.healthyColor;
    const healthLevel = node.data('healthLevel');
    if (healthLevel === 2) {
      midColor = this.colors.warnColor;
    } else if (healthLevel === 3) {
      midColor = this.colors.dangerColor;
    }
    // console.log('midColor:', midColor);
    // 底层白
    ctx.fillStyle = 'white';
    ctx.fillRect(cX, cY, width + strokeWidth * 2, long + strokeWidth);
    // 中间层
    ctx.fillStyle = midColor;
    ctx.fillRect(cX + strokeWidth, cY + strokeWidth / 2, width, long);
    // 中间层白
    ctx.fillStyle = 'white';
    ctx.fillRect(
      cX + storkeWidth2,
      cY + storkeWidth2 / 2,
      width - storkeWidth2 * 2 + strokeWidth * 2,
      long - storkeWidth2 + +strokeWidth
    );
    // 第一层
    if (node.selected()) {
      ctx.fillStyle = 'white';
    } else {
      ctx.fillStyle = this.colors.background;
    }
    ctx.fillRect(
      cX + strokeWidth + storkeWidth2,
      cY + (strokeWidth + storkeWidth2) / 2,
      width - storkeWidth2 * 2,
      long - storkeWidth2
    );
  }


  // 画圆
  _drawDonut(
    ctx: CanvasRenderingContext2D,
    node: cytoscape.NodeSingular,
    radius: number,
    width: number,
    strokeWidth: number,
    percentages: number[]
  ) {
    const cX = node.position().x;
    const cY = node.position().y;
    let currentArc = -Math.PI / 2; // offset

    // 最底层白边
    ctx.beginPath();
    ctx.arc(cX, cY, radius + strokeWidth, 0, 2 * Math.PI, false);
    ctx.closePath();
    ctx.fillStyle = 'white';
    ctx.fill();

    const colors = [this.colors.dangerColor, this.colors.noDataColor, this.colors.healthyColor];
    for (let i = 0; i < percentages.length; i++) {
      let arc = this._drawArc(ctx, currentArc, cX, cY, radius, percentages[i], colors[i]);
      currentArc += arc;
    }

    ctx.beginPath();
    ctx.arc(cX, cY, radius - width, 0, 2 * Math.PI, false);
    ctx.fillStyle = 'white';
    ctx.fill();

    // cut out an inner-circle == donut 切出一个内圆 == 甜甜圈
    ctx.beginPath();
    ctx.arc(cX, cY, radius - width - strokeWidth, 0, 2 * Math.PI, false);
    if (node.selected()) {
      ctx.fillStyle = 'white';
    } else {
      ctx.fillStyle = this.colors.background;
    }
    ctx.fill();
  }

  _drawArc(
    ctx: CanvasRenderingContext2D,
    currentArc: number,
    cX: number,
    cY: number,
    radius: number,
    percent: number,
    color: string
  ) {
    // calc size of our wedge in radians 以弧度计算楔形的大小
    var WedgeInRadians = (percent * 360 * Math.PI) / 180;
    // draw the wedge
    // 保存画布 (canvas) 的所有状态
    ctx.save();
    ctx.beginPath();
    // 将笔触移动到指定的坐标 x 以及 y 上。
    ctx.moveTo(cX, cY);
    ctx.arc(cX, cY, radius, currentArc, currentArc + WedgeInRadians, false);
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
    ctx.restore();
    return WedgeInRadians;
  }
}
