import { DataFrame } from '@grafana/data';
import _ from 'lodash';
import { PanelController } from '../panel/PanelController';
import { CurrentData, GlobalElement, GraphDataElement, GraphDataType } from '../types';

// 预处理器
class PreProcessor {
  controller: PanelController;

  constructor(controller: PanelController) {
    this.controller = controller;
  }

  // 转换对象
  _transformObjects(data: any): GlobalElement {
    // const { aggregationType } = this.controller.getSettings(true).dataMapping;
    // console.log('data:', data);
    // console.log('data[result]', data.result);
    // console.log('data[suggestions]', data.suggestions);
    var grahDateElementArray: GraphDataElement[] = [];
    var fp = data.footprints;
    // console.log('fp:', fp);
    var replyFa = fp.filter((dataObject: { [x: string]: boolean }) => dataObject['reply'] === false);
    var replyTr = fp.filter((dataObject: { [x: string]: boolean }) => dataObject['reply'] === true);
    // console.log('replyFa:', replyFa);
    // console.log('replyTr:', replyTr);
    this._transformObject(grahDateElementArray, replyFa, replyTr);
    this._transformObject(grahDateElementArray, replyTr, replyFa);
    // console.log('grahDateElementArray:', grahDateElementArray);
    const filteredResult: GraphDataElement[] = grahDateElementArray.filter(
      (element): element is GraphDataElement => element !== null
    );
    // console.log('filteredResult:', filteredResult);
    const globalElement: GlobalElement = {
      graphDataElement: filteredResult,
      result: data.result,
      suggestions: data.suggestions,
    };

    return globalElement;
  }

  _transformObject(gr: GraphDataElement[], data: any[], data2: any[]): GraphDataElement[] {
    let packIsEmpty = false; // 记录上一条数据的packet是否为空
    if (data.length < 2) {
      // 如果要处理的数组长度小于2
      if (data.length === 0) {
        return gr;
      }
      if (data[0]['reply'] === false) {
        // 如果处理的是reply=false数据
        const element: GraphDataElement = {
          target: '',
          type: GraphDataType.INTERNAL,
        };
        let dataArray: any[] = [];
        for (let data2Element of data2) {
          if (data2Element['interface'] !== data[0]['interface'] || data2Element['host'] !== data[0]['host']) {
            element.source = data2Element['interface'] + '-' + data2Element['host'];
            break;
          }
        }
        element.target = data[0]['interface'] + '-' + data[0]['host'];
        dataArray.push(data[0]);
        element.data = dataArray;
        gr.push(element);
        return gr;
      } else {
        // 如果处理的是reply=true数据
        const element: GraphDataElement = {
          target: '',
          type: GraphDataType.INTERNAL,
        };
        let dataArray: any[] = [];
        for (let i = data2.length - 1; i >= 0; i--) {
          if (data2[i]['interface'] !== data[0]['interface'] || data2[i]['host'] !== data[0]['host']) {
            element.source = data2[i]['interface'] + '-' + data2[i]['host'];
            break;
          }
        }
        element.target = data[0]['interface'] + '-' + data[0]['host'];
        dataArray.push(data[0]);
        element.data = dataArray;
        gr.push(element);
        return gr;
      }
    } else {
      // 有多条数据的情况
      for (let i = 0; i <= data.length - 2; i++) {
        const element: GraphDataElement = {
          target: '',
          type: GraphDataType.INTERNAL,
        };
        let dataArray: any[] = [];
        element.source = data[i]['interface'] + '-' + data[i]['host'];
        element.target = data[i + 1]['interface'] + '-' + data[i + 1]['host'];
        if (!packIsEmpty) {
          // 如果上条数据packet为空，则不记录这条数据的data,因为上一条数据已经记录了
          // console.log('data[i + 1]:', data[i + 1]);
          dataArray.push(data[i]);
        }
        if (data[i].packet === null || i == data.length - 2) {
          // 如果当前数据packet为空，则data要push下一条数据的data
          dataArray.push(data[i + 1]);
          packIsEmpty = true;
        } else {
          packIsEmpty = false;
        }
        element.data = dataArray;
        gr.push(element);
      }
    }
    return gr;
  }

  //合并图数据
  _mergeGraphData(globalElement: GlobalElement): GlobalElement {
    const data: GraphDataElement[] = globalElement.graphDataElement;
    const groupedData = _.values(_.groupBy(data, (element) => element.source + '<--->' + element.target));
    const mergedData = _.map(groupedData, (group) => {
      return _.reduce(group, (result, next) => {
        return _.merge(result, next);
      });
    });
    globalElement.graphDataElement = mergedData;

    return globalElement;
  }

  // 提取列名
  _extractColumnNames(globalElement: GlobalElement): string[] {
    const data: GraphDataElement[] = globalElement.graphDataElement;
    const columnNames: string[] = _(data)
      .flatMap((dataElement) => _.keys(dataElement.data[0]))
      .uniq()
      .sort()
      .value();

    return columnNames;
  }

  _getField(fieldName: string, fields: any[]) {
    for (const field of fields) {
      if (field.name === fieldName) {
        return field;
      }
    }
    return undefined;
  }

  // 提取数据
  _dataToRows(inputDataSets: any) {
    var rowDatas: any[] = [];
    for (const inputData of inputDataSets) {
      const { fields } = inputData;
      // if (!_.has(dataElement, 'columns')) {
      //   result = false;
      // }
      const footprints = _.find(fields, ['name', 'footprints']);
      const result = _.find(fields, ['name', 'result']);
      const suggestions = _.find(fields, ['name', 'suggestions']);
      for (let i = 0; i < inputData.length; i++) {
        const rowData: any = {};
        rowData['footprints'] = footprints?.values.get(i);
        rowData['result'] = result?.values.get(i);
        rowData['suggestions'] = suggestions?.values.get(i);
        rowDatas.push(rowData);
      }
    }
      const foot = rowDatas[0]['footprints'];
      const rows = JSON.parse(foot);
      var rowDas: any = {};
      rowDas['footprints'] = rows;
      rowDas['result'] = rowDatas[0]['result'];
      rowDas['suggestions'] = rowDatas[0]['suggestions'];
      // console.log('rowDas:', rowDas);
      return rowDas;
  
  }

  // 处理数据
  processData(inputData: DataFrame[]): CurrentData {
    // console.log('rows:', rows);
    const rowDas = this._dataToRows(inputData);
    // console.log('rowDas:', rowDas);
    // console.log('flattenData:', flattenData);
    const globalElements = this._transformObjects(rowDas);
    // console.log('globalElements:', globalElements);
    // 提取列名
    const columnNames = this._extractColumnNames(globalElements);
    // console.log('columnNames:', columnNames);
    // 合并图数据
    const mergedData = this._mergeGraphData(globalElements);
    // console.log('mergedData:', mergedData);
    return {
      globalElement: mergedData,
      raw: inputData,
      columnNames: columnNames,
    };
  }
}

export default PreProcessor;
