import React from 'react';
import { NodeStatistics } from './NodeStatistics';
import '../../css/novatec-service-dependency-graph-panel.css';
import './Statistics.css';
import { FootPrints, IntSelectionStatistics } from 'types';
// import roundPercentageToDecimal from './utils/Utils';

interface StatisticsProps {
  show: boolean;
  selectionId: string | number;
  interfaceName: string;
  interfaceIp: string;
  result: string;
  suggestion: string;
  resolvedDrillDownLink: string;
  selectionStatistics: IntSelectionStatistics;
  currentType: string;
  receiving: FootPrints[];
  sending: FootPrints[];
}

export const Statistics: React.FC<StatisticsProps> = ({
  show,
  selectionId,
  interfaceName,
  interfaceIp,
  result,
  suggestion,
  resolvedDrillDownLink,
  selectionStatistics,
  currentType,
  receiving,
  sending,
}) => {
  var statisticsClass = 'statistics';
  var statistics = <div></div>;
  if (show) {
    statisticsClass = 'statistics show ';
    var drilldownLink = <div></div>;
    if (resolvedDrillDownLink && resolvedDrillDownLink.length > 0 && currentType === 'INTERNAL') {
      drilldownLink = (
        <a target="_blank" rel="noreferrer" href={resolvedDrillDownLink}>
          <i className="fa fa-paper-plane-o margin"></i>
        </a>
      );
    }

    const itName = interfaceName ? (
      <tr>
        <td className="table--td--selection">InterfaceName</td>
        <td className="table--td--selection">{interfaceName}</td>
      </tr>
    ) : null;

    const itIP = interfaceIp ? (
      <tr>
        <td className="table--td--selection">InterfaceIp</td>
        <td className="table--td--selection">{interfaceIp}</td>
      </tr>
    ) : null;

    const res = result ? (
      <tr>
        <td className="table--td--selection">result</td>
        <td className="table--td--selection">{result}</td>
      </tr>
    ) : null

    const sug = suggestion ? (
      <tr>
        <td className="table--td--selection">suggestion</td>
        <td className="table--td--selection">{suggestion}</td>
      </tr>
    ) : null

    statistics = (
      <div className="statistics">
        <div className="header--selection">
          {selectionId}
          {drilldownLink}
        </div>

        <div className="secondHeader--selection">Statistics</div>
        <table className="table--selection">
          <tr className="table--selection--head">
            <th>Name</th>
            <th className="table--th--selectionMedium">Value</th>
          </tr>
          {itName}
          {itIP}
          {res}
          {sug}
        </table>

        <NodeStatistics nodeList={receiving} noDataText="No request Footprints." title="request Footprints" />
        <NodeStatistics nodeList={sending} noDataText="No reply Footprints." title="reply Footprints" />
      </div>
    );
  }

  return <div className={statisticsClass}>{statistics}</div>;
};
